solution_code:
#include <iostream>

int main() {
    int threshold;
    std::cin >> threshold;

    auto isAbove = [threshold](int x) { return x > threshold; };

    int n;
    std::cin >> n;

    int count = 0;
    for (int i = 0; i < n; ++i) {
        int val;
        std::cin >> val;
        if (isAbove(val)) ++count;
    }

    std::cout << "Count: " << count << "\n";
    return 0;
}

