#include <iostream>

int main() {
    int total = 0;
    // Bug: captures by value (mutable copy) instead of by reference
    // total in main never changes
    auto addTo = [total](int x) mutable { total += x; };

    int n;
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        int val;
        std::cin >> val;
        addTo(val);
    }

    std::cout << total << "\n";
    return 0;
}

solution_code:
#include <iostream>

int main() {
    int total = 0;
    auto addTo = [&total](int x) { total += x; };

    int n;
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        int val;
        std::cin >> val;
        addTo(val);
    }

    std::cout << total << "\n";
    return 0;
}
